module top_module(
    input        clk,
    input        clr,
    input  [3:0] A,
    input  [3:0] B,
    input        sub,
    output [3:0] Y
);reg [3:0] unused_temp;

    always @(posedge clk)
        if (clr) unused_temp <= 4'b0;
        else if (sub) unused_temp <= A - B;
        else unused_temp <= A + B;

    assign Y = unused_temp;

endmodule
